        "import pandas as pd\n",
        "import matplotlib.pyplot as plt\n",
        "import os\n",
        "\n",
        "def run_visualization():\n",
        "    #  Setup\n",
        "    try:\n",
        "        df = pd.read_csv('data/trends_analysed.csv')\n",
        "        if not os.path.exists('outputs'):\n",
        "            os.makedirs('outputs')\n",
        "            print(\"Created 'outputs/' folder.\")\n",
        "    except FileNotFoundError:\n",
        "        print(\"Error: trends_analysed.csv not found. Run Task 3 first!\")\n",
        "        return\n",
        "\n",
        "    # 2. Chart 1: Top 10 Stories by Score\n",
        "    plt.figure(figsize=(10, 6))\n",
        "    top_10 = df.sort_values('score', ascending=False).head(10)\n",
        "\n",
        "    # Shorten titles to 50 chars for the y-axis\n",
        "    clean_titles = [t[:47] + \"...\" if len(t) > 50 else t for t in top_10['title']]\n",
        "\n",
        "    plt.barh(clean_titles, top_10['score'], color='skyblue')\n",
        "    plt.gca().invert_yaxis() # Put the #1 story at the top\n",
        "    plt.title(\"Top 10 Most Upvoted Stories\")\n",
        "    plt.xlabel(\"Upvote Score\")\n",
        "    plt.ylabel(\"Story Title\")\n",
        "    plt.tight_layout()\n",
        "    plt.savefig('outputs/chart1_top_stories.png')\n",
        "    plt.show()\n",
        "\n",
        "    # 3. Chart 2: Stories per Category\n",
        "    plt.figure(figsize=(8, 5))\n",
        "    cat_counts = df['category'].value_counts()\n",
        "\n",
        "    # Using a list of distinct colors\n",
        "    colors = ['#FF9999', '#66B2FF', '#99FF99', '#FFCC99', '#C2C2F0']\n",
        "    cat_counts.plot(kind='bar', color=colors[:len(cat_counts)])\n",
        "\n",
        "    plt.title(\"News Distribution by Category\")\n",
        "    plt.xlabel(\"Category\")\n",
        "    plt.ylabel(\"Number of Stories\")\n",
        "    plt.xticks(rotation=45)\n",
        "    plt.tight_layout()\n",
        "    plt.savefig('outputs/chart2_categories.png')\n",
        "    plt.show()\n",
        "\n",
        "    #  Chart 3: Score vs Comments\n",
        "    plt.figure(figsize=(8, 6))\n",
        "\n",
        "    # Scatter plot logic: popular stories get a different color\n",
        "    for popular_status, color, label in [(True, 'gold', 'Popular'), (False, 'grey', 'Regular')]:\n",
        "        mask = df['is_popular'] == popular_status\n",
        "        plt.scatter(df.loc[mask, 'score'],\n",
        "                    df.loc[mask, 'num_comments'],\n",
        "                    c=color, label=label, alpha=0.6, edgecolors='black')\n",
        "\n",
        "    plt.title(\"Engagement: Score vs. Comments\")\n",
        "    plt.xlabel(\"Score (Upvotes)\")\n",
        "    plt.ylabel(\"Number of Comments\")\n",
        "    plt.legend()\n",
        "    plt.grid(True, linestyle='--', alpha=0.5)\n",
        "    plt.savefig('outputs/chart3_scatter.png')\n",
        "    plt.show()\n",
        "\n",
        "    # --- BONUS Dashboard\n",
        "    # Creating a 2x2 grid (leaving one spot empty or spanning across)\n",
        "    fig, axs = plt.subplots(2, 2, figsize=(16, 12))\n",
        "    fig.suptitle('TrendPulse Dashboard: HackerNews Insights', fontsize=22, fontweight='bold')\n",
        "\n",
        "    # Slot 1: Top 10\n",
        "    axs[0, 0].barh(clean_titles, top_10['score'], color='skyblue')\n",
        "    axs[0, 0].invert_yaxis()\n",
        "    axs[0, 0].set_title(\"Top 10 Stories\")\n",
        "\n",
        "    # Slot 2: Categories\n",
        "    cat_counts.plot(kind='bar', ax=axs[0, 1], color=colors[:len(cat_counts)])\n",
        "    axs[0, 1].set_title(\"Stories per Category\")\n",
        "\n",
        "    # Slot 3: Scatter (bottom left)\n",
        "    for popular_status, color in [(True, 'gold'), (False, 'grey')]:\n",
        "        mask = df['is_popular'] == popular_status\n",
        "        axs[1, 0].scatter(df.loc[mask, 'score'], df.loc[mask, 'num_comments'], c=color, alpha=0.5)\n",
        "    axs[1, 0].set_title(\"Score vs Comments\")\n",
        "\n",
        "    # Slot 4: Simple Summary text\n",
        "    axs[1, 1].axis('off')\n",
        "    summary_text = f\"Total Stories: {len(df)}\\nAvg Score: {df['score'].mean():.1f}\\nMost Active: {cat_counts.idxmax()}\"\n",
        "    axs[1, 1].text(0.5, 0.5, summary_text, fontsize=15, ha='center', va='center', bbox=dict(facecolor='white', alpha=0.5))\n",
        "\n",
        "    plt.tight_layout(rect=[0, 0.03, 1, 0.95])\n",
        "    plt.savefig('outputs/dashboard.png')\n",
        "    print(\"All charts and dashboard saved to the 'outputs/' folder!\")\n",
        "\n",
        "if __name__ == \"__main__\":\n",
        "    run_visualization()"
